    LCSuff = [[0 for k in range(n+1)] for l in range(m+1)] 
    result = 0
    for i in range(m + 1): 
        for j in range(n + 1): 
            if (i == 0 or j == 0): 
                LCSuff[i][j] = 0
            elif s1[i-1] == s2[j-1]: 
                LCSuff[i][j] = LCSuff[i-1][j-1] + 1
