  self.root = None

 # Insert a node 
 def insert(self, data):
  if self.root == None:
   self.root = Node(data)
  else:
   self._insert(data, self.root)

 # Helper function for Node Insert
 def _insert(self, data, cur_node):
  if data < cur_node.data: 
   if cur_node.left == None: 
    cur_node.left = Node(data) 
   else: 
    self._insert(data, cur_node.left)
  elif data > cur_node.data: 
   if cur_node.right == None: 
    cur_node.right = Node(data) 
   else: 
    self._insert(data, cur_node.right) 
  else: 
   pass

# Search a node
def search(self, data):
 if self.root != None:
  return self._search(data, self.root)
 else:
  return False

# Helper function for Node Search
def _search(self, data, cur_node):
 if data > cur_node.data and cur_node.right != None:
  return self._search(data, cur_node.right)
 elif data < cur_node.data and cur_node.left != None:
  return self._search(data, cur_node.left)
 elif data == cur_node.data:
  return True

