def findLongestCommonSubsequence(s1, s2): 

    # Initialize L[][] 
    L = [[0 for x in range(len(s2)+1)] 
                for x in range(len(s1)+1)] 

    # Traverse the strings 
    for i in range(len(s1)+1): 
        for j in range(len(s2)+1): 

            # If strings have matching characters 
            if i == 0 or j == 0 : 
                L[i][j] = 0

            elif s1[i-1] == s2[j-1]: 
                L[i][j] = L[i-1][j-1] + 1

            else: 
                L[i][j] = max(L[i-1][j], 
                               L[i][j-1]) 

    print("Length of Longest Common Subsequence is ", 
                              L[len(s1)][len(s2)])

def find_palindromes(s):
    n = len(s)
    is_palindrome = [[False for _ in range(n)] for _ in range(n)]

    # Palindrome of length 1
    for i in range(n):
        is_palindrome[i][i] = True
    # Palindrome of length 2
    for i in range(n - 1):
        is_palindrome[i][i + 1] = (s[i] == s[i + 1])
    # Palindrome of length >= 3
    for length in range(3, n + 1):
        for i in range(n - length + 1):
            j = i + length - 1
            if s[i] == s[j] and is_palindrome[i + 1][j - 1]:
                is_palindrome[i][j] = True
    res = []
    for i in range(n):
        for j in range(i, n):
            if is_palindrome[i][j] and j - i + 1 >= 3:
                res.append(s[i:j + 1])
    return res

