import sys, serial

class HardwareController:
    """
    This class allows users to access and control additional hardware components which are connected to the computer via USB.
    """

    def __init__(self):
        self.serial_port = None
        self.baud_rate = None

    # Establish connection between computer and hardware component
    def connect(self, serial_port, baud_rate):
        try: 
            self.serial_port = serial.Serial(serial_port, baud_rate)
            self.baud_rate = baud_rate
            return True
        except:
            # Return false and print error if connection fails
            print("Error: Failed to connect to the device. Check baud rate and serial port.")
            return False

    # Write data to the hardware component
    def write(self, data):
        if self.serial_port.isOpen():
            self.serial_port.write(data)
        else:
            print("Error: Device is not connected. Connect to the device first and try again.")

    # Read data from the hardware component
    def read(self):
        if self.serial_port.isOpen():
            return self.serial_port.readline()
        else:
            print("Error: Device is not connected. Connect to the device first and try again.")

    # Disconnect from the hardware component
    def disconnect(self):
        self.serial_port.close()
        self.serial_port = None

def permutations(input_list):
    if len(input_list) == 1:
        return input_list
    output_list = []
    for value in input_list:
        temp_list = input_list[:]
        temp_list.remove(value)
        permutations_list = permutations(temp_list)
        for sub_list in permutations_list:
            output_list.append([value] + sub_list)
    return output_list

