def flatten_dict(nested_dict, flat_dict={}, prefix=''):
    for key, value in nested_dict.items():
        key_prefix = prefix + key + '.' if prefix else key

        if isinstance(value, dict):
            flatten_dict(value, flat_dict, key_prefix)
        else:
            flat_dict[key_prefix] = value

    return flat_dict

