def quick_sort(input_list):
    if len(input_list) <= 1:
        return input_list
    pivot = input_list[0]
    left = [x for x in input_list[1:] if x < pivot]
    right = [x for x in input_list[1:] if x >= pivot]
    return quick_sort(left) + [pivot] + quick_sort(right)

