def is_anagram(s1, s2):
    # remove all whitespaces and make it lower case
    s1 = ''.join(s1.split()).lower()
    s2 = ''.join(s2.split()).lower()

    # edge case check
    if len(s1) != len(s2):
        return False

    # count occurrences of each character
    count = {}
    for char in s1:
        if char in count:
            count[char] += 1
        else:
            count[char] = 1

    for char in s2:
        if char in count:
            count[char] -= 1
        else:
            return False

    # check that count of each character is zero
    for k in count:
        if count[k] != 0:
            return False

    return True

