def gcd(a,b): 

    # Everything divides 0  
    if (a == 0 or b == 0): 
        return 0; 

    # base case 
    if (a == b): 
        return a 

    # a is greater 
    if (a > b): 
        return gcd(a-b, b) 

    return gcd(a, b-a) 

