    def __init__(self):
        self.coef_ = None

    def fit(self, X, y):
        n, m = X.shape
        w = np.random.randn(m)
        lr = 10e-5
        for t in range(1000):
            p = np.dot(X, w)
            grad = 2 * np.dot(X.T, p - y) + lr * np.sign(w)
            w = w - lr * grad
        self.coef_ = w

