def prime_factorize(n): 

    prime_factors = [] 

    d = 2
    while d*d <= n: 
        while (n % d) == 0: 
            prime_factors.append(d)  
            n /= d 
        d += 1

    if n > 1: 
        prime_factors.append(n)

    return prime_factors 

