def deepest_node(root):
    if not root:
        return 0
    elif not root.left and not root.right:
        return 1
    else:
        left_depth = deepest_node(root.left)
        right_depth = deepest_node(root.right)

        if left_depth > right_depth:
            return 1 + left_depth
        else:
            return 1 + right_depth

