class MinHeap:
    def __init__(self):
        self.heap= []

    def parent(self, i):
        return int((i - 1) / 2)

    def insertKey(self, k):
        self.heap.append(k)     
        i = len(self.heap)-1
        self.fix_up(i)

    def fix_up(self, i):
        while i != 0 and self.heap[self.parent(i)] > self.heap[i]:
            self.heap[i], self.heap[self.parent(i)] = self.heap[self.parent(i)], self.heap[i]
            i = self.parent(i)

    def extractMin(self):
        if len(self.heap) == 0:
            return -1
        min_elem = self.heap[0]
        if len(self.heap) > 1:
            self.heap[0] = self.heap.pop()
            self.fix_down(0)
        else:
            self.heap.pop()
        return min_elem

    def fix_down(self, i):
        left = 2*i + 1
        right = 2*i + 2
        min_i = i
        if left < len(self.heap) and self.heap[min_i] > self.heap[left]:
            min_i = left
        if right < len(self.heap) and self.heap[min_i] > self.heap[right]:
            min_i = right
        if min_i != i:
            self.heap[min_i], self.heap[i] = self.heap[i], self.heap[min_i]
            self.fix_down(min_i)

