def int_to_roman(num):
    num_map = {  
        1: 'I',
        5: 'V',
        10: 'X',
        50: 'L',
        100: 'C',
        500: 'D',
        1000: 'M'
    }
    roman = ''
    if num in num_map:
        roman = num_map[num]
    else:
        if num < 4:
            roman = 'I'*num
        elif num < 9:
            roman = 'I' + 'V'*(num-5)
        elif num < 40:
            roman = 'X' + 'I'*(num-10)
        elif num < 50:
            roman = 'XL' + 'I'*(num-40)
        elif num < 90:
            roman = 'L' + 'X'*(num-50)
        elif num < 100:
            roman = 'XC' + 'X'*(num-90)
        elif num < 400:
            roman = 'C' + 'X'*(num-100)
        elif num < 500:
            roman = 'CD' + 'C'*(num-400)
        elif num < 900:
            roman = 'D' + 'C'*(num-500)
        elif num < 1000:
            roman = 'CM' + 'C'*(num-900)
        elif num > 1000:
            roman = 'M' + 'M'*(num-1000)
    return roman

