"""
Create a Python code to implement the "Edit Distance" algorithm to compare two strings and output their edit distance.
""" 

def edit_distance(str1, str2):
    # create a matrix for storing the results
    matrix = [[0 for x in range(len(str1) + 1)] for x in range(len(str2) + 1)]

    # initialize the matrix
    for i in range(len(str2) + 1):
        matrix[i][0] = i

    for j in range(len(str1) + 1):
        matrix[0][j] = j

    # fill the matrix
    for i in range(1, len(str2) + 1):
        for j in range(1, len(str1) + 1):
            if str2[i - 1] == str1[j - 1]:
                matrix[i][j] = matrix[i - 1][j - 1]
            else:
                matrix[i][j] = min(matrix[i - 1][j], matrix[i][j - 1], matrix[i - 1][j - 1]) + 1

    return matrix[len(str2)][len(str1)]

