def sort_linked_list(head):
    if not head or head.next is None:
        return head

    mid = get_middle(head)
    mid_next = mid.next

    l1 = sort_linked_list(head)
    l2 = sort_linked_list(mid_next)

    return merge(l1, l2)

def merge(l1, l2):
    if l1 is None:
        return l2
    if l2 is None:
        return l1
    if l1.val < l2.val:
        l1.next = merge(l1.next, l2)
        return l1
    else:
        l2.next = merge(l1, l2.next)
        return l2

def get_middle(head):
    if not head:
        return head

    slow = head
    fast = head

    while fast.next and fast.next.next:
        slow = slow.next
        fast = fast.next.next
    return slow

