def encrypt_caesar(text, shift):
    """Encrypt the text using the Caesar cipher"""
    encrypted_text = ""
    for char in text:
        if char.isalpha():
            encrypted_char = chr(ord(char) + shift)
            if encrypted_char.isalpha():
                encrypted_text += encrypted_char
            else:
                encrypted_text += chr(ord(encrypted_char) - 26)
        else:
            encrypted_text += char
    return encrypted_text

