def evaluate_suduku(board):
    rows = len(board)
    cols = len(board[0])
    # Check rows
    for row in board:
        if not all_unique(row):
            return False
    # Check columns
    for i in range(cols):
        column = [row[i] for row in board]
        if not all_unique(column):
            return False
    # Check 3x3 boxes
    for i in range(0,rows-2,3):
        for j in range(0,cols-2,3):
            box = []
            for row in board[i:i+3]:
                for num in row[j:j+3]:
                    box.append(num)
            if not all_unique(box):
                return False
    return True

