from math import sqrt

def quadratic_roots(a, b, c):
    # calculate the discriminant
    D = b**2 - 4*a*c

    # calculate the two roots
    if D == 0:
        return (-b+sqrt(D)) // (2*a)
    else:
        x1 = (-b + sqrt(D)) // (2*a)
        x2 = (-b - sqrt(D)) // (2*a)
        return (x1, x2)

