class Sort:
    def __init__(self, lst):
        self.lst = lst

    def bubble_sort(self):
        length = len(self.lst)
        for i in range(length):
            for j in range(length - i -1):
                if self.lst[j] > self.lst[j + 1]:
                    self.lst[j], self.lst[j + 1] = self.lst[j + 1], self.lst[j]
        return self.lst

