class TicTacToe:
    def __init__(self):
        self.board = [[None] * 3 for _ in range(3)]

    def player_move(self, row, col, move):
        self.board[row][col] = move
        return self.check_for_win(row, col, move)

    def check_for_win(self, row, col, move):
        # Check row and column
        row_win = all(move == self.board[row][i] for i in range(3))
        col_win = all(move == self.board[i][col] for i in range(3))

        # Check diagonal
        diag_win = row == col and all(move == self.board[i][i] for i in range(3))
        diag_win_2 = (row + col) == 2 and all(move == self.board[2-i][i] for i in range(3))

        if row_win or col_win or diag_win or diag_win_2:
            return True
        else:
            return False

