def findMinCoins(coins, amount):
    dp = [0] * (amount + 1)
    dp[0] = 0

    for i in range(1, amount + 1):
        dp[i] = float('inf') 
        for j in range(len(coins)):
            if (coins[j] <= i):
                res = dp[i - coins[j]]
                if (res != float('inf') and res + 1 < dp[i]):
                    dp[i] = res + 1
    return dp[amount]

