class Node:
    def __init__(self, val):
        self.val = val
        self.left = None
        self.right = None

class BinarySearchTree:
    def __init__(self):
        self.root = None

    def add(self, val):
        new_node = Node(val)
        if not self.root:
            self.root = new_node
        else:
            curr = self.root
            while True:
                if val < curr.val:
                    if not curr.left:
                        curr.left = new_node
                        break
                    curr = curr.left
                else:
                    if not curr.right:
                        curr.right = new_node
                        break
                    curr = curr.right
        return self.root

    def search(self, val):
        curr = self.root
        while curr:
            if val < curr.val:
                curr = curr.left
            elif val > curr.val:
                curr = curr.right
            else:
                return curr
        return False

class MergeTwoLists():
    def merge(self, left_list, right_list):
        """Merge two sorted lists"""
        i = 0
        j = 0
        merged_list = []
        while i < len(left_list) and j < len(right_list):
            if left_list[i] < right_list[j]:
                merged_list.append(left_list[i])
                i += 1
            else:
                merged_list.append(right_list[j])
                j += 1

        merged_list += left_list[i:]
        merged_list += right_list[j:]
        return merged_list

