import nltk 

def classify_words(words):
    # initialize empty dictionaries
    nouns = {}
    verbs = {}

    # extract parts-of-speech
    for word in words:
        pos = nltk.pos_tag([word])[0][1]
        # add to nouns or verbs
        if pos.startswith('N'):
            nouns[word] = pos
        elif pos.startswith('V'):
            verbs[word] = pos

    return nouns,verbs

