        return n + sum_recursive(n-1)

print(sum_recursive(10))

def max_three_nums(arr):
    max_three = []

    for i in range(3):
        max_element = 0 
        for j in range(len(arr)): 
            if max_element < arr[j]:
                max_element = arr[j] 
        arr.remove(max_element) 
        max_three.append(max_element) 
    return max_three 

arr = [7, 9, 15, 10, 11] 
print(max_three_nums(arr))

class Book:
